// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "https://github.com/OpenZeppelin/openzeppelin-contracts/blob/v5.4.0/contracts/token/ERC20/IERC20.sol";
import "https://github.com/OpenZeppelin/openzeppelin-contracts/blob/v5.4.0/contracts/token/ERC20/utils/SafeERC20.sol";
import "https://github.com/OpenZeppelin/openzeppelin-contracts/blob/v5.4.0/contracts/access/Ownable.sol";
import "https://github.com/OpenZeppelin/openzeppelin-contracts/blob/v5.4.0/contracts/utils/ReentrancyGuard.sol";

interface IElectroFarm {
    struct Farmer {
        address addr;
        uint256 liquidity;
        uint256 boltMultiplier;
        uint256 boltDeposited;
        uint256 durationMultiplier;
        uint256 startingBlock;
        uint256 rewards;
        uint256 rewardDebt;
        uint256 thirdPartyRewards;
        uint256 thirdPartyRewardDebt;
        uint256 fees0;
        uint256 fees0Debt;
        uint256 fees1;
        uint256 fees1Debt;
    }

    function deposit(
        uint256 farmId,
        uint256 amount0,
        uint256 amount1,
        uint256 amountBolt
    ) external payable;

    function withdraw(
        uint256 farmId,
        uint256 liquidityAmt,
        bool asNative
    ) external;

    function getFarmerByFarmIdAndAddress(
        uint256 farmId,
        address farmer
    ) external view returns (Farmer memory);
}

interface IRouter {
    function swapExactTokensForTokensSupportingFeeOnTransferTokens(
        uint amountIn,
        uint amountOutMin,
        address[] calldata path,
        address to,
        uint deadline
    ) external;
}

interface ICoreToken {
    function burn(uint256 amount) external;
}

contract ZephyrosCoreBurnVault is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    uint256 public constant PRECISION = 1e18;
    uint256 public constant LOCK_DURATION = 90 days;

    uint256 public burnBps = 4000;     // 40%
    uint256 public rewardBps = 4500;   // 45%
    uint256 public treasuryBps = 1500; // 15%

    address public constant BURN_ADDRESS = address(0);

    IERC20 public immutable token0;
    IERC20 public immutable token1;
    IERC20 public immutable core;
    ICoreToken public immutable coreBurn;
    IERC20 public immutable rewardToken;

    IElectroFarm public immutable electroFarm;
    IRouter public immutable router;

    uint256 public immutable farmId;
    address public treasury;

    uint256 public totalLiquidity;
    uint256 public accCorePerLiquidity;

    struct UserInfo {
        uint256 liquidity;
        uint256 coreLocked;
        uint256 rewardDebt;
        uint256 unlockTime;
        bool active;
    }

    mapping(address => UserInfo) public users;

    event Deposited(
        address indexed user,
        uint256 amount0,
        uint256 amount1,
        uint256 coreLocked,
        uint256 liquidityAdded,
        uint256 unlockTime
    );

    event Withdrawn(
        address indexed user,
        uint256 liquidityRemoved,
        uint256 coreUnlocked
    );

    event Harvested(
        uint256 rewardAmount,
        uint256 coreBought,
        uint256 coreBurned,
        uint256 coreRewards,
        uint256 coreTreasury
    );

    event CoreRewardsClaimed(address indexed user, uint256 amount);

    constructor(
        address _token0,
        address _token1,
        address _core,
        address _rewardToken,
        address _electroFarm,
        address _router,
        uint256 _farmId,
        address _treasury
    ) Ownable(msg.sender) {
        require(_token0 != address(0), "token0 zero");
        require(_token1 != address(0), "token1 zero");
        require(_core != address(0), "core zero");
        require(_rewardToken != address(0), "reward zero");
        require(_electroFarm != address(0), "farm zero");
        require(_router != address(0), "router zero");
        require(_treasury != address(0), "treasury zero");

        token0 = IERC20(_token0);
        token1 = IERC20(_token1);
        core = IERC20(_core);
        coreBurn = ICoreToken(_core);
        rewardToken = IERC20(_rewardToken);

        electroFarm = IElectroFarm(_electroFarm);
        router = IRouter(_router);

        farmId = _farmId;
        treasury = _treasury;
    }

    function deposit(
        uint256 amount0,
        uint256 amount1,
        uint256 coreLockAmount
    ) external nonReentrant {
        require(amount0 > 0 && amount1 > 0, "zero deposit");
        require(coreLockAmount > 0, "CORE lock required");

        UserInfo storage user = users[msg.sender];

        _claimCoreRewards(msg.sender);

        token0.safeTransferFrom(msg.sender, address(this), amount0);
        token1.safeTransferFrom(msg.sender, address(this), amount1);
        core.safeTransferFrom(msg.sender, address(this), coreLockAmount);

        // TODO:
        // Replace this with proper LP value pricing.
        // For production, coreLockAmount must be >= 10% of LP value in CORE.
        require(
            _isValidCoreLock(amount0, amount1, coreLockAmount),
            "Insufficient CORE lock"
        );

        token0.forceApprove(address(electroFarm), amount0);
        token1.forceApprove(address(electroFarm), amount1);

        uint256 beforeLiquidity =
            electroFarm
                .getFarmerByFarmIdAndAddress(farmId, address(this))
                .liquidity;

        electroFarm.deposit(farmId, amount0, amount1, 0);

        uint256 afterLiquidity =
            electroFarm
                .getFarmerByFarmIdAndAddress(farmId, address(this))
                .liquidity;

        uint256 liquidityAdded = afterLiquidity - beforeLiquidity;
        require(liquidityAdded > 0, "no liquidity added");

        user.liquidity += liquidityAdded;
        user.coreLocked += coreLockAmount;
        user.unlockTime = block.timestamp + LOCK_DURATION;
        user.active = true;

        totalLiquidity += liquidityAdded;

        user.rewardDebt =
            (user.liquidity * accCorePerLiquidity) /
            PRECISION;

        emit Deposited(
            msg.sender,
            amount0,
            amount1,
            coreLockAmount,
            liquidityAdded,
            user.unlockTime
        );
    }

    function withdraw(uint256 liquidityAmount) external nonReentrant {
        UserInfo storage user = users[msg.sender];

        require(liquidityAmount > 0, "zero withdraw");
        require(user.liquidity >= liquidityAmount, "too much");
        require(block.timestamp >= user.unlockTime, "still locked");

        _claimCoreRewards(msg.sender);

        uint256 coreToUnlock =
            (user.coreLocked * liquidityAmount) /
            user.liquidity;

        user.liquidity -= liquidityAmount;
        user.coreLocked -= coreToUnlock;
        totalLiquidity -= liquidityAmount;

        electroFarm.withdraw(farmId, liquidityAmount, false);

        if (user.liquidity == 0) {
            user.active = false;
            user.rewardDebt = 0;
        } else {
            user.rewardDebt =
                (user.liquidity * accCorePerLiquidity) /
                PRECISION;
        }

        core.safeTransfer(msg.sender, coreToUnlock);

        emit Withdrawn(msg.sender, liquidityAmount, coreToUnlock);
    }

    function harvest(
        address[] calldata rewardToCorePath,
        uint256 minCoreOut
    ) external nonReentrant {
        require(totalLiquidity > 0, "no liquidity");

        uint256 beforeReward = rewardToken.balanceOf(address(this));

        // Withdraw 0 liquidity from ElectroSwap farm to harvest rewards.
        electroFarm.withdraw(farmId, 0, false);

        uint256 rewardAmount =
            rewardToken.balanceOf(address(this)) - beforeReward;

        require(rewardAmount > 0, "nothing harvested");

        rewardToken.forceApprove(address(router), rewardAmount);

        uint256 beforeCore = core.balanceOf(address(this));

        router.swapExactTokensForTokensSupportingFeeOnTransferTokens(
            rewardAmount,
            minCoreOut,
            rewardToCorePath,
            address(this),
            block.timestamp
        );

        uint256 coreBought = core.balanceOf(address(this)) - beforeCore;

        uint256 burnAmount = (coreBought * burnBps) / 10_000;
        uint256 rewardAmountCore = (coreBought * rewardBps) / 10_000;
        uint256 treasuryAmount = coreBought - burnAmount - rewardAmountCore;

        coreBurn.burn(burnAmount);
        core.safeTransfer(treasury, treasuryAmount);

        accCorePerLiquidity +=
            (rewardAmountCore * PRECISION) /
            totalLiquidity;

        emit Harvested(
            rewardAmount,
            coreBought,
            burnAmount,
            rewardAmountCore,
            treasuryAmount
        );
    }

    function claimCoreRewards() external nonReentrant {
        _claimCoreRewards(msg.sender);
    }

    function pendingCoreRewards(address account) public view returns (uint256) {
        UserInfo memory user = users[account];

        if (user.liquidity == 0) return 0;

        uint256 accumulated =
            (user.liquidity * accCorePerLiquidity) /
            PRECISION;

        return accumulated - user.rewardDebt;
    }

    function isCharacterEligible(address account) external view returns (bool) {
        UserInfo memory user = users[account];

        return
            user.active &&
            user.liquidity > 0 &&
            user.coreLocked > 0 &&
            block.timestamp >= user.unlockTime;
    }

    function _claimCoreRewards(address account) internal {
        UserInfo storage user = users[account];

        if (user.liquidity == 0) return;

        uint256 pending = pendingCoreRewards(account);

        if (pending > 0) {
            core.safeTransfer(account, pending);
            emit CoreRewardsClaimed(account, pending);
        }

        user.rewardDebt =
            (user.liquidity * accCorePerLiquidity) /
            PRECISION;
    }

    function _isValidCoreLock(
        uint256 amount0,
        uint256 amount1,
        uint256 coreLockAmount
    ) internal pure returns (bool) {
        amount0;
        amount1;

        // Placeholder only.
        // Production version must calculate:
        // CORE lock >= 10% of deposited LP value.
        return coreLockAmount > 0;
    }

    function setSplits(
        uint256 _burnBps,
        uint256 _rewardBps,
        uint256 _treasuryBps
    ) external onlyOwner {
        require(
            _burnBps + _rewardBps + _treasuryBps == 10_000,
            "bad split"
        );

        require(_burnBps >= 3000, "burn too low");

        burnBps = _burnBps;
        rewardBps = _rewardBps;
        treasuryBps = _treasuryBps;
    }

    function setTreasury(address _treasury) external onlyOwner {
        require(_treasury != address(0), "zero treasury");
        treasury = _treasury;
    }
}

